190	struct StatementExecutor : public ast::ASTVisitor<StatementExecutor, ast::VisitFlags::Statements>
191	{
192	public:
193		NetlistContext &netlist;
194		ProceduralContext &context;
195		EvalContext &eval;
196		UnrollLimitTracking &unroll_limit;
197		const ast::StatementBlockSymbol *containing_block = nullptr;
198	
199		StatementExecutor(ProceduralContext &context)
200			: netlist(context.netlist), context(context), eval(context.eval),
201			  unroll_limit(context.unroll_limit)
202		{}
203	
204		void handle(const ast::ImmediateAssertionStatement &statement)
205		{
206			if (netlist.settings.ignore_assertions.value_or(false))
207				return;
208	
209			std::string flavor;
210			switch (statement.assertionKind) {
211			case ast::AssertionKind::Assert:        flavor = "assert"; break;
212			case ast::AssertionKind::Assume:        flavor = "assume"; break;
213			case ast::AssertionKind::CoverProperty: flavor = "cover"; break;
214			default:                                netlist.add_diag(diag::AssertionUnsupported, statement.sourceRange); return;
215			}
216	
217			RTLIL::IdString cell_name;
218	
219			if (containing_block &&
220					unwrap_statement(containing_block->tryGetStatement()) == &statement &&
221					!containing_block->name.empty()) {
222				// If we are the sole statement in a block, use the block's label
223				cell_name = netlist.id(*containing_block);
224			} else {
225				cell_name = netlist.new_id();
226			}
227	
228			auto cell = netlist.canvas->addCell(cell_name, ID($check));
229	
230			context.set_effects_trigger(cell);
231			cell->setParam(ID::FLAVOR, flavor);
232			cell->setParam(ID::FORMAT, std::string(""));
233			cell->setParam(ID::ARGS_WIDTH, 0);
234			cell->setParam(ID::PRIORITY, --context.effects_priority);
235			cell->setPort(ID::ARGS, {});
236			cell->setPort(ID::A, netlist.ReduceBool(eval(statement.cond)));
237			transfer_attrs(netlist, statement, cell);
238		}
239	
240		void handle(const ast::ConcurrentAssertionStatement &statement)
241		{
242			if (!netlist.settings.ignore_assertions.value_or(false)) {
243				if (statement.assertionKind == ast::AssertionKind::Expect) {
244					netlist.add_diag(diag::ExpectStatementUnsupported, statement.sourceRange);
245				} else {
246					process_sva_property(statement, containing_block, context, statement.propertySpec);
247				}
248			}
249		}
250	
251		RTLIL::SigSpec handle_call(const ast::CallExpression &call)
252		{
253			RTLIL::SigSpec ret;
254	
255			require(call, !call.isSystemCall());
256			auto subroutine = std::get<0>(call.subroutine);
257			auto arg_symbols = subroutine->getArguments();
258	
259			std::vector<RTLIL::SigSpec> arg_in, arg_out;
260	
261			for (int i = 0; i < (int)arg_symbols.size(); i++) {
262				const ast::Expression *arg = call.arguments()[i];
263				auto dir = arg_symbols[i]->direction;
264	
265				if (dir == ast::ArgumentDirection::In || dir == ast::ArgumentDirection::InOut)
266					arg_in.push_back(eval(*arg));
267				else
268					arg_in.push_back({});
269			}
270	
271			slang::SourceLocation loc = call.sourceRange.start();
272	
273			{
274				EnterAutomaticScopeGuard scope_guard(eval, subroutine);
275	
276				for (auto &member : subroutine->members())
277					if (ast::VariableSymbol::isKind(member.kind)) {
278						auto &var = member.as<ast::VariableSymbol>();
279	
280						if (var.kind == ast::SymbolKind::FormalArgument ||
281								var.flags.has(ast::VariableFlags::CompilerGenerated))
282							var.visit(*this);
283					}
284	
285				for (int i = 0; i < (int)arg_symbols.size(); i++) {
286					auto dir = arg_symbols[i]->direction;
287					if (dir == ast::ArgumentDirection::In || dir == ast::ArgumentDirection::InOut)
288						context.do_simple_assign(loc, eval.variable(*arg_symbols[i]), arg_in[i], true);
289				}
290	
291				{
292					RegisterEscapeConstructGuard escape_guard(
293							context, EscapeConstructKind::FunctionBody, subroutine);
294					subroutine->getBody().visit(*this);
295				}
296	
297				for (int i = 0; i < (int)arg_symbols.size(); i++) {
298					auto dir = arg_symbols[i]->direction;
299					if (dir == ast::ArgumentDirection::Out || dir == ast::ArgumentDirection::InOut)
300						arg_out.push_back(context.substitute_rvalue(eval.variable(*arg_symbols[i])));
301					else
302						arg_out.push_back({});
303				}
304	
305				if (subroutine->returnValVar)
306					ret = context.substitute_rvalue(eval.variable(*subroutine->returnValVar));
307			}
308	
309			for (int i = 0; i < (int)arg_symbols.size(); i++) {
310				const ast::Expression *arg = call.arguments()[i];
311				auto dir = arg_symbols[i]->direction;
312	
313				if (dir == ast::ArgumentDirection::Out || dir == ast::ArgumentDirection::InOut)
314					context.assign_rvalue(arg->as<ast::AssignmentExpression>(), arg_out[i]);
315			}
316	
317			return ret;
318		}
319	
320		void handle(const ast::ExpressionStatement &stmt) { eval(stmt.expr); }
321	
322		void handle(const ast::BlockStatement &blk)
323		{
324			require(blk, blk.blockKind == ast::StatementBlockKind::Sequential)
325					EnterAutomaticScopeGuard guard(context.eval, blk.blockSymbol);
326	
327			if (blk.blockSymbol) {
328				ast_invariant(*blk.blockSymbol, blk.blockSymbol->tryGetStatement() == &blk);
329				const ast::StatementBlockSymbol *symbol_save = containing_block;
330				containing_block = blk.blockSymbol;
331				blk.body.visit(*this);
332				containing_block = symbol_save;
333			} else {
334				blk.body.visit(*this);
335			}
336		}
337	
338		void handle(const ast::StatementList &list)
339		{
340			Variable disable = context.get_disable_flag();
341	
342			std::vector<SwitchHelper> sw_stack;
343	
344			for (auto &stmt : list.list) {
345				RTLIL::SigSpec disable_rv = disable ? context.substitute_rvalue(disable) : RTLIL::S0;
346				if (!disable_rv.is_fully_const()) {
347					auto &b = sw_stack.emplace_back(context, disable_rv);
348					b.sw->statement = stmt;
349					b.enter_branch({RTLIL::S0});
350					context.current_case->statement = stmt;
351	
352					// From a semantical POV the following is a no-op, but it allows us to
353					// do more constant folding.
354					context.do_simple_assign(
355							slang::SourceLocation::NoLocation, disable, RTLIL::S0, true);
356				} else if (disable_rv.as_bool()) {
357					break;
358				} else {
359					log_assert(!disable_rv.as_bool());
360				}
361	
362				stmt->visit(*this);
363			}
364	
365			for (auto it = sw_stack.rbegin(); it != sw_stack.rend(); it++) {
366				it->exit_branch();
367				it->finish(netlist);
368			}
369		}
370	
371		void handle(const ast::ConditionalStatement &cond)
372		{
373			require(cond, cond.conditions.size() == 1);
374			require(cond, cond.conditions[0].pattern == NULL);
375	
376			RTLIL::SigSpec condition = netlist.ReduceBool(eval(*cond.conditions[0].expr));
377	
378			if (condition.is_fully_def()) {
379				if (condition[0] == RTLIL::S1) {
380					cond.ifTrue.visit(*this);
381					return;
382				} else if (condition[0] == RTLIL::S0) {
383					if (cond.ifFalse)
384						cond.ifFalse->visit(*this);
385					return;
386				}
387				// fall through on Sx
388			}
389	
390			SwitchHelper b(context, condition);
391			b.sw->statement = &cond;
392	
393			b.branch({RTLIL::S1}, [&]() {
394				context.current_case->statement = &cond.ifTrue;
395				cond.ifTrue.visit(*this);
396			});
397	
398			if (cond.ifFalse) {
399				b.branch({}, [&]() {
400					context.current_case->statement = cond.ifFalse;
401					cond.ifFalse->visit(*this);
402				});
403			}
404			b.finish(netlist);
405	
406			// descend into an empty switch so we force action priority for follow-up statements
407			context.current_case = context.current_case->add_switch({})->add_case({});
408		}
409	
410		void handle(const ast::CaseStatement &stmt)
411		{
412			bool match_x, match_z;
413			using Condition = ast::CaseStatementCondition;
414			switch (stmt.condition) {
415			case Condition::WildcardJustZ:
416				match_x = false;
417				match_z = true;
418				break;
419			case Condition::WildcardXOrZ: match_x = match_z = true; break;
420			default:                      match_x = match_z = false; break;
421			}
422	
423			RTLIL::SigSpec dispatch = eval(stmt.expr);
424			SwitchHelper b(context, stmt.condition == ast::CaseStatementCondition::Inside
425											? RTLIL::SigSpec(RTLIL::S1)
426											: dispatch);
427	
428			b.sw->statement = &stmt;
429			switch (stmt.check) {
430			case ast::UniquePriorityCheck::Priority: b.sw->full_case = true; break;
431			case ast::UniquePriorityCheck::Unique:
432				b.sw->full_case = true;
433				b.sw->parallel_case = true;
434				break;
435			case ast::UniquePriorityCheck::Unique0: b.sw->parallel_case = true; break;
436			case ast::UniquePriorityCheck::None:    break;
437			}
438	
439			for (auto item : stmt.items) {
440				std::vector<RTLIL::SigSpec> compares;
441				for (auto expr : item.expressions) {
442					log_assert(expr);
443	
444					if (stmt.condition == ast::CaseStatementCondition::Inside) {
445						require(stmt, stmt.expr.type->isIntegral());
446						compares.push_back(inside_comparison(eval, dispatch, *expr));
447						continue;
448					}
449	
450					RTLIL::SigSpec compare = eval(*expr);
451					log_assert(compare.size() == dispatch.size());
452					require(stmt, !match_z || compare.is_fully_const());
453					for (int i = 0; i < compare.size(); i++) {
454						if (compare[i] == RTLIL::Sz && match_z)
455							compare[i] = RTLIL::Sa;
456						if (compare[i] == RTLIL::Sx && match_x)
457							compare[i] = RTLIL::Sa;
458					}
459					compares.push_back(compare);
460				}
461				require(stmt, !compares.empty());
462				b.branch(compares, [&]() {
463					context.current_case->statement = item.stmt;
464					item.stmt->visit(*this);
465				});
466			}
467	
468			if (stmt.defaultCase) {
469				b.branch(std::vector<RTLIL::SigSpec>{}, [&]() {
470					context.current_case->statement = stmt.defaultCase;
471					stmt.defaultCase->visit(*this);
472				});
473			}
474			b.finish(netlist);
475	
476			// descend into an empty switch so we force action priority for follow-up statements
477			context.current_case = context.current_case->add_switch({})->add_case({});
478		}
479	
480		void handle(const ast::WhileLoopStatement &stmt)
481		{
482			RegisterEscapeConstructGuard guard1(context, EscapeConstructKind::Loop, &stmt);
483			std::vector<SwitchHelper> sw_stack;
484			unroll_limit.enter_unrolling();
485			while (true) {
486				RTLIL::SigSpec cv = netlist.ReduceBool(eval(stmt.cond));
487				RTLIL::SigSpec break_rv = context.vstate.evaluate(netlist, guard1.flag);
488				RTLIL::SigSpec joint_break = netlist.LogicOr(netlist.LogicNot(cv), break_rv);
489	
490				if (!joint_break.is_fully_const()) {
491					auto &b = sw_stack.emplace_back(context, joint_break);
492					b.sw->statement = &stmt;
493					b.enter_branch({RTLIL::S0});
494					context.current_case->statement = &stmt.body;
495	
496					// From a semantical POV the following is a no-op, but it allows us to
497					// do more constant folding.
498					context.do_simple_assign(
499							slang::SourceLocation::NoLocation, guard1.flag, RTLIL::S0, true);
500				} else if (joint_break.as_bool()) {
501					break;
502				} else {
503					log_assert(!joint_break.as_bool());
504				}
505	
506				{
507					RegisterEscapeConstructGuard guard2(context, EscapeConstructKind::LoopBody, &stmt);
508					stmt.body.visit(*this);
509				}
510	
511				if (!unroll_limit.unroll_tick(&stmt))
512					break;
513			}
514			unroll_limit.exit_unrolling();
515	
516			for (auto it = sw_stack.rbegin(); it != sw_stack.rend(); it++) {
517				it->exit_branch();
518				it->finish(netlist);
519			}
520	
521			context.current_case = context.current_case->add_switch({})->add_case({});
522		}
523	
524		void handle(const ast::ForLoopStatement &stmt)
525		{
526			for (auto init : stmt.initializers)
527				eval(*init);
528	
529			if (!stmt.stopExpr) {
530				netlist.add_diag(diag::MissingStopCondition, stmt.sourceRange.start());
531				return;
532			}
533	
534			RegisterEscapeConstructGuard guard1(context, EscapeConstructKind::Loop, &stmt);
535	
536			std::vector<SwitchHelper> sw_stack;
537			unroll_limit.enter_unrolling();
538			while (true) {
539				RTLIL::SigSpec cv = netlist.ReduceBool(eval(*stmt.stopExpr));
540	
541				if (!cv.is_fully_const()) {
542					auto &b = sw_stack.emplace_back(context, cv);
543					b.sw->statement = &stmt;
544					b.enter_branch({RTLIL::S1});
545					context.current_case->statement = &stmt.body;
546				} else if (!cv.as_bool()) {
547					break;
548				} else {
549					log_assert(cv.as_bool());
550				}
551	
552				{
553					RegisterEscapeConstructGuard guard2(context, EscapeConstructKind::LoopBody, &stmt);
554					stmt.body.visit(*this);
555				}
556	
557				RTLIL::SigSpec break_rv = context.substitute_rvalue(guard1.flag);
558	
559				if (!break_rv.is_fully_const()) {
560					auto &b = sw_stack.emplace_back(context, break_rv);
561					b.sw->statement = &stmt;
562					b.enter_branch({RTLIL::S0});
563					context.current_case->statement = &stmt.body;
564				} else if (break_rv.as_bool()) {
565					break;
566				} else {
567					log_assert(!break_rv.as_bool());
568				}
569	
570				for (auto step : stmt.steps)
571					eval(*step);
572	
573				if (!unroll_limit.unroll_tick(&stmt))
574					break;
575			}
576			unroll_limit.exit_unrolling();
577	
578			for (auto it = sw_stack.rbegin(); it != sw_stack.rend(); it++) {
579				it->exit_branch();
580				it->finish(netlist);
581			}
582	
583			context.current_case = context.current_case->add_switch({})->add_case({});
584		}
585	
586		void handle(const ast::ForeachLoopStatement &stmt)
587		{
588			auto set_iterator_value = [this, &stmt](const ast::VariableSymbol &target, int32_t value) {
589				context.do_simple_assign(
590						stmt.sourceRange.start(), eval.variable(target), RTLIL::Const(value, 32), true);
591			};
592	
593			std::vector<SwitchHelper> sw_stack;
594			std::vector<std::optional<int32_t>> loopVarStack(stmt.loopDims.size(), std::nullopt);
595			// Initialize loop vars ranges
596			for (size_t i = 0; i < stmt.loopDims.size(); ++i) {
597				auto loopDim = stmt.loopDims[i];
598				if (loopDim.loopVar && loopDim.range) {
599					loopVarStack[loopVarStack.size() - i - 1] = loopDim.range->left;
600					set_iterator_value(*loopDim.loopVar, loopDim.range->left);
601				}
602			}
603	
604			std::vector<slang::ast::ForeachLoopStatement::LoopDim> reversedDims(
605					stmt.loopDims.rbegin(), stmt.loopDims.rend());
606	
607			RegisterEscapeConstructGuard guard1(context, EscapeConstructKind::Loop, &stmt);
608			unroll_limit.enter_unrolling();
609			while (true) {
610				{
611					RegisterEscapeConstructGuard guard2(context, EscapeConstructKind::LoopBody, &stmt);
612					stmt.body.visit(*this);
613				}
614	
615				RTLIL::SigSpec break_rv = context.substitute_rvalue(guard1.flag);
616	
617				if (!break_rv.is_fully_const()) {
618					auto &b = sw_stack.emplace_back(context, break_rv);
619					b.sw->statement = &stmt;
620					b.enter_branch({RTLIL::S0});
621					context.current_case->statement = &stmt.body;
622				} else if (break_rv.as_bool()) {
623					break;
624				} else {
625					log_assert(!break_rv.as_bool());
626				}
627	
628				bool doBreak = true;
629				for (size_t i = 0; i < loopVarStack.size(); ++i) {
630					if (!loopVarStack[i])
631						continue;
632	
633					if (*loopVarStack[i] != reversedDims[i].range->right) {
634						*loopVarStack[i] = *loopVarStack[i] > reversedDims[i].range->right
635												   ? *loopVarStack[i] - 1
636												   : *loopVarStack[i] + 1;
637						doBreak = false;
638						break;
639					} else if (i != loopVarStack.size() - 1) {
640						bool nextDimFound = false;
641						size_t j = i + 1;
642						for (; j < loopVarStack.size(); ++j) {
643							if (loopVarStack[j] && *loopVarStack[j] != reversedDims[j].range->right) {
644								nextDimFound = true;
645								break;
646							}
647						}
648	
649						if (nextDimFound) {
650							*loopVarStack[j] = *loopVarStack[j] > reversedDims[j].range->right
651													   ? *loopVarStack[j] - 1
652													   : *loopVarStack[j] + 1;
653							doBreak = false;
654							for (size_t k = 0; k < j; ++k) {
655								if (loopVarStack[k])
656									*loopVarStack[k] = reversedDims[k].range->left;
657							}
658	
659							break;
660						}
661					}
662				}
663	
664				for (size_t i = 0; i < loopVarStack.size(); ++i) {
665					if (loopVarStack[i]) {
666						auto currDim = reversedDims[i];
667						set_iterator_value(*currDim.loopVar, *loopVarStack[i]);
668					}
669				}
670	
671				if (doBreak || !unroll_limit.unroll_tick(&stmt))
672					break;
673			}
674			unroll_limit.exit_unrolling();
675	
676			for (auto it = sw_stack.rbegin(); it != sw_stack.rend(); it++) {
677				it->exit_branch();
678				it->finish(netlist);
679			}
680	
681			context.current_case = context.current_case->add_switch({})->add_case({});
682		}
683	
684		void handle(const ast::EmptyStatement &) {}
685	
686		void init_nonstatic_variable(const ast::ValueSymbol &symbol)
687		{
688			Variable target = eval.variable(symbol);
689			log_assert((bool)target);
690	
691			if (!target.bitwidth())
692				return;
693	
694			RTLIL::SigSpec initval;
695			if (symbol.getInitializer()) {
696				initval = eval(*symbol.getInitializer());
697			} else {
698				auto converted =
699						netlist.convert_const(symbol.getType().getDefaultValue(), symbol.location);
700				if (converted) {
701					initval = *converted;
702				} else {
703					initval = {RTLIL::Sx, (int)target.bitwidth()};
704				}
705			}
706			context.do_simple_assign(symbol.location, target, initval, true);
707		}
708	
709		void handle(const ast::VariableSymbol &symbol)
710		{
711			if (symbol.lifetime != ast::VariableLifetime::Static) {
712				init_nonstatic_variable(symbol);
713			}
714		}
715		void handle(const ast::VariableDeclStatement &stmt) { stmt.symbol.visit(*this); }
716	
717		void handle(const ast::BreakStatement &brk)
718		{
719			context.signal_escape(brk.sourceRange.start(), EscapeConstructKind::Loop);
720		}
721	
722		void handle(const ast::ContinueStatement &brk)
723		{
724			context.signal_escape(brk.sourceRange.start(), EscapeConstructKind::LoopBody);
725		}
726	
727		void handle(const ast::ReturnStatement &stmt)
728		{
729			auto subroutine = context.get_current_subroutine();
730			log_assert(subroutine);
731	
732			if (stmt.expr) {
733				ast_invariant(stmt, subroutine->subroutineKind == ast::SubroutineKind::Function);
734				log_assert(subroutine->returnValVar);
735				context.do_simple_assign(stmt.sourceRange.start(),
736						eval.variable(*subroutine->returnValVar), eval(*stmt.expr), true);
737			}
738	
739			context.signal_escape(stmt.sourceRange.start(), EscapeConstructKind::FunctionBody);
740		}
741	
742		void handle(const ast::TimedStatement &stmt)
743		{
744			if (!netlist.settings.ignore_timing.value_or(false))
745				netlist.add_diag(diag::GenericTimingUnsyn, stmt.timing.sourceRange);
746	
747			stmt.stmt.visit(*this);
748		}
749	
750		void handle(const ast::WaitStatement &stmt)
751		{
752			netlist.add_diag(diag::WaitStatementUnsupported, stmt.sourceRange);
753		}
754	
755		void handle(const ast::Statement &stmt)
756		{
757			netlist.add_diag(diag::LangFeatureUnsupported, stmt.sourceRange.start());
758		}
759	
760		void handle(const ast::Expression &expr) { unimplemented(expr); }
761	};
762	
763	}; // namespace slang_frontend
