312	
313	RTLIL::SigSpec ProceduralContext::substitute_rvalue(VariableBits bits)
314	{
315		RTLIL::SigSpec subed;
316	
317		if (timing.kind == ProcessTiming::Initial) {
318			// No non-blocking assignments allowed in initial procedures.
319			for (auto [base, size, chunk] : bits.chunk_spans()) {
320				switch (chunk.variable.kind) {
321				case Variable::Dummy:
322				case Variable::Invalid: log_abort();
323	
324				case Variable::Local:
325				case Variable::EscapeFlag:
326					for (uint64_t i = 0; i < size; i++) {
327						subed.append(initial_locals_state.at(chunk[i], RTLIL::Sx));
328					}
329					break;
330				case Variable::Static:
331					for (uint64_t i = 0; i < size; i++) {
332						subed.append(netlist.initial_state.at(chunk[i], RTLIL::Sx));
333					}
334					break;
335				default: log_abort();
336				}
337			}
338		} else {
339			for (auto chunk : bits.chunks()) {
340				// We disallow mixing of blocking and non-blocking assignments to the
341				// same variable from the same process. That simplifies the handling
342				// here.
343				if (chunk.variable.kind != Variable::Static ||
344						seen_blocking_assignment.count(chunk.variable))
345					subed.append(vstate.evaluate(netlist, chunk));
346				else
347					subed.append(netlist.convert_static(chunk));
348			}
349		}
350	
351		return subed;
352	}
353	
354	void assign_to_lvalue_with_masking(const ast::AssignmentExpression &assign,
355			ProceduralContext &context, LValue &lvalue, RTLIL::SigSpec rvalue, RTLIL::SigSpec mask,
356			bool blocking)
357	{
358		if (lvalue.is_static()) {
359			context.update_variable_state(
360					assign.sourceRange.start(), lvalue.evaluate_vbits(), rvalue, mask, blocking);
361			return;
362		}
363	
364		if (auto concat = std::get_if<LValue::Concatenation>(&lvalue.descriptor)) {
365			uint64_t base = lvalue.bitsize;
366			for (auto &el : concat->elements) {
367				base -= el.bitsize;
368				assign_to_lvalue_with_masking(assign, context, el, rvalue.extract(base, el.bitsize),
369						mask.extract(base, el.bitsize), blocking);
370			}
371			log_assert(base == 0);
372		} else if (auto range_sel = std::get_if<LValue::RangeSelect>(&lvalue.descriptor)) {
373			if ((uint64_t)range_sel->resolver->stride == lvalue.bitsize) {
374				// Effectively an element select
375				assign_to_lvalue_with_masking(assign, context, *range_sel->inner,
376						rvalue.repeat(range_sel->resolver->range.width()),
377						range_sel->resolver->demux(mask, range_sel->inner->bitsize), blocking);
378			} else {
379				assign_to_lvalue_with_masking(assign, context, *range_sel->inner,
380						range_sel->resolver->shift_up(rvalue, true, range_sel->inner->bitsize),
381						range_sel->resolver->shift_up(mask, false, range_sel->inner->bitsize),
382						blocking);
383			}
384		} else if (auto member_acc = std::get_if<LValue::MemberAccess>(&lvalue.descriptor)) {
385			uint64_t parent_width = member_acc->inner->bitsize;
386			uint64_t pad = parent_width - lvalue.bitsize - member_acc->base_offset;
387			assign_to_lvalue_with_masking(assign, context, *member_acc->inner,
388					{RTLIL::SigSpec(RTLIL::Sx, pad), rvalue,
389							RTLIL::SigSpec(RTLIL::Sx, member_acc->base_offset)},
390					{RTLIL::SigSpec(RTLIL::S0, pad), mask,
391							RTLIL::SigSpec(RTLIL::S0, member_acc->base_offset)},
392					blocking);
393		} else if (auto mem_write = std::get_if<LValue::MemoryWrite>(&lvalue.descriptor)) {
394			auto &netlist = context.netlist;
395			RTLIL::Cell *cell = netlist.canvas->addCell(netlist.new_id(), ID($memwr_v2));
396			std::string id = netlist.id(*mem_write->target.get_symbol());
397			cell->setParam(ID::MEMID, id);
398			auto &timing = context.timing;
399			if (timing.kind == ProcessTiming::Implicit) {
400				cell->setParam(ID::CLK_ENABLE, false);
401				cell->setParam(ID::CLK_POLARITY, false);
402				cell->setPort(ID::CLK, RTLIL::Sx);
403			} else if (timing.kind == ProcessTiming::EdgeTriggered) {
404				require(assign, timing.triggers.size() == 1);
405				auto &trigger = timing.triggers[0];
406				cell->setParam(ID::CLK_ENABLE, true);
407				cell->setParam(ID::CLK_POLARITY, trigger.edge_polarity);
408				cell->setPort(ID::CLK, trigger.signal);
409			} else {
410				ast_unreachable(assign);
411			}
412	
413			int portid = context.netlist.emitted_mems[id].num_wr_ports++;
414			cell->setParam(ID::PORTID, portid);
415			std::vector<RTLIL::State> prio_mask(portid, RTLIL::S0);
416			auto &preceding_memwr = context.preceding_memwr;
417			for (auto prev : preceding_memwr) {
418				log_assert(prev->type == ID($memwr_v2));
419				if (prev->getParam(ID::MEMID) == cell->getParam(ID::MEMID)) {
420					prio_mask[prev->getParam(ID::PORTID).as_int()] = RTLIL::S1;
421				}
422			}
423			preceding_memwr.push_back(cell);
424	
425			cell->setParam(ID::PRIORITY_MASK, prio_mask);
426			cell->setPort(
427					ID::EN, netlist.Mux(RTLIL::SigSpec(RTLIL::S0, mask.size()), mask,
428									netlist.LogicAnd(context.case_enable(), timing.background_enable)));
429			cell->setParam(ID::ABITS, mem_write->address.size());
430			cell->setPort(ID::ADDR, mem_write->address);
431			cell->setParam(ID::WIDTH, rvalue.size());
432			cell->setPort(ID::DATA, rvalue);
433		} else {
434			// unreachable
435			log_abort();
436		}
437	}
438	
439	void ProceduralContext::assign_rvalue(
440			const ast::AssignmentExpression &assign, RTLIL::SigSpec rvalue)
441	{
442		if (assign.timingControl && !netlist.settings.ignore_timing.value_or(false))
443			netlist.add_diag(diag::GenericTimingUnsyn, assign.timingControl->sourceRange);
444	
445		bool blocking = !assign.isNonBlocking();
446		const ast::Expression *raw_lexpr = &assign.left();
447	
448		if (raw_lexpr->kind == ast::ExpressionKind::Streaming) {
449			auto &stream_lexpr = raw_lexpr->as<ast::StreamingConcatenationExpression>();
450			VariableBits lvalue = eval.streaming_lhs(stream_lexpr);
451			ast_invariant(assign, (uint64_t)rvalue.size() >= lvalue.bitwidth());
452			do_simple_assign(assign.sourceRange.start(), lvalue,
453					rvalue.extract_end(rvalue.size() - lvalue.bitwidth()), blocking);
454			return;
455		} else if (raw_lexpr->kind == ast::ExpressionKind::SimpleAssignmentPattern) {
456			// break down into individual assignments
457			auto &pattern_lexpr = raw_lexpr->as<ast::SimpleAssignmentPatternExpression>();
458	
459			int nbits_remaining = rvalue.size();
460			for (auto el : pattern_lexpr.elements()) {
461				log_assert(el->kind == ast::ExpressionKind::Assignment);
462				auto &inner_assign = el->as<ast::AssignmentExpression>();
463	
464				const ast::Expression *rsymbol = &inner_assign.right();
465				while (rsymbol->kind == ast::ExpressionKind::Conversion)
466					rsymbol = &rsymbol->as<ast::ConversionExpression>().operand();
467				log_assert(rsymbol->kind == ast::ExpressionKind::EmptyArgument);
468				log_assert(rsymbol->type->isBitstreamType());
469				int relem_width = rsymbol->type->getBitstreamWidth();
470	
471				log_assert(nbits_remaining >= relem_width);
472				RTLIL::SigSpec relem = rvalue.extract(nbits_remaining - relem_width, relem_width);
473				nbits_remaining -= relem_width;
474	
475				assign_rvalue(inner_assign, eval.apply_nested_conversion(inner_assign.right(), relem));
476			}
477	
478			log_assert(nbits_remaining == 0);
479			return;
480		}
481		auto analyzed_lvalue = LValue::analyze(this->eval, *raw_lexpr, false);
482		if (analyzed_lvalue) {
483			assign_to_lvalue_with_masking(assign, *this, *analyzed_lvalue, rvalue,
484					RTLIL::SigSpec(RTLIL::S1, rvalue.size()), blocking);
485		}
486	}
487	
488	Variable ProceduralContext::get_disable_flag()
489	{
490		if (escape_stack.empty())
491			return Variable();
492		else
493			return escape_stack.back().flag;
494	}
495	
496	UnrollLimitTracking::UnrollLimitTracking(NetlistContext &netlist, int limit)
497		: netlist(netlist), limit(limit)
498	{}
499	
500	UnrollLimitTracking::~UnrollLimitTracking()
501	{
502		log_assert(!unrolling);
503	}
504	
505	void UnrollLimitTracking::enter_unrolling()
506	{
507		if (!unrolling++) {
508			unroll_counter = 0;
509			error_issued = false;
510			loops.clear();
511		}
512	}
513	
514	void UnrollLimitTracking::exit_unrolling()
515	{
516		unrolling--;
517		log_assert(unrolling >= 0);
518	}
519	
520	bool UnrollLimitTracking::unroll_tick(const ast::Statement *symbol)
521	{
522		if (error_issued)
523			return false;
524	
525		loops.insert(symbol);
526	
527		if (++unroll_counter > limit) {
528			auto &diag = netlist.add_diag(diag::UnrollLimitExhausted, symbol->sourceRange);
529			diag << limit;
530			for (auto other_loop : loops) {
531				if (other_loop == symbol)
532					continue;
533				diag.addNote(diag::NoteLoopContributes, other_loop->sourceRange);
534			}
535			error_issued = true;
536			return false;
537		}
538	
539		return true;
540	}
541	
542	}; // namespace slang_frontend
